export const UpdateTodos = (props) => {
    const { completeTodos, onClickBack } = props;

    return (
        <div>
            <ul>
            {completeTodos.map((done, index) => (
            <li key={done}>
                <p>{done}</p>
                <button onClick={() => onClickBack(index)}>戻す</button>
            </li>
                )
            )}
            </ul>
        </div>
    )
}
